from device import RecommendedDeviceSettings


def charachorder():
    recommendations = [('CMD', 'Lists available commands.'), ('ID', 'Identifies device, such as CHARACHORDER ONE M0.'), ('VERSION', 'Returns the current firmware version, such as 1.1.1.'), ('CML', 'Used for getting, setting (adding or overwriting), and deleting chordmaps.'), ('CML C0', 'Gets the (decimal) number of chordmaps.'), ('CML C1', 'Gets a chordmap by the index number (hexadecimal uint16) if within range.'), ('CML C2', 'Gets a chordmap by the chord (hexadecimal) value if it is found in the library.'), ('CML C3', 'Sets a chordmap with a chord and output bytes (hexadecimal).'), ('CML C4', 'Deletes a chordmap from the library if the chord exists.'), ('VAR', 'Used for getting and settings parameters; this includes setting custom chordmaps.'), ('VAR B0', 'Commits any parameter changes to persistent memory.'), ('VAR B1', 'Gets the value of a parameter.'), ('VAR B2', 'Sets the value of a parameter.'), ('VAR B3', 'Gets the value of a key in a keymap.'), ('VAR B4', 'Sets the value of a key in a keymap.'), ('RST', 'Restarts/reboots the microcontroller hardware. It has additional arguments for Factory and Bootloader.'), ('RST RESTART', 'Restarts the microcontroller.'),
                       ('RST FACTORY', 'Performs a factory reset of the flash and emulated eeprom. During the process, the flash chip is erased.'), ('RST BOOTLOADER', 'Restarts the device into a bootloader mode.'), ('RST PARAMS', 'Resets the parameters to factory defaults and commits.'), ('RST KEYMAPS', 'Resets the keymaps to the factory defaults and commits.'), ('RST STARTER', 'Adds starter chordmaps. This does not clear the chordmap library, but adds to it, replacing those that have the same chord.'), ('RST CLEARCML', 'Permanently deletes all the chordmaps stored in the device memory.'), ('RST UPGRADECML', 'Attempts to upgrade chordmaps that the system detects are older. This is under development.'), ('RST FUNC', 'Adds back in functional chords such as CAPSLOCKS and Backspace-X chords.'), ('RAM', 'Prints the current amount of SRAM available; this is primarily used for debugging.'), ('SIM', 'Simulates/injects a chord and outputs the chord output if the chord exists in the chord library; this is primarily used for debugging.'), ('SIM CHORD', 'Injects a chord to be processed by the device.'), ('SIM KEYSTATE', 'Injects key states to be processed by the device.')]

    return RecommendedDeviceSettings(baud_rate=115200, auto_new_line=True, auto_return_carry=True, throttle_ms=100, auto_complete_suggestions=recommendations)
